"use client"

import { useState, useEffect, useRef } from "react"
import Image from "next/image"
import { getProfile, saveProfile, hydrateStore, Profile } from "@/lib/store"
import { useAdmin } from "@/lib/admin-context"
import { AdminLoginDialog } from "@/components/admin-login-dialog"
import { Button } from "@/components/ui/button"
import { Textarea } from "@/components/ui/textarea"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Camera, Edit2, Save, X } from "lucide-react"

export default function ProfilePage() {
  const { isAdmin } = useAdmin()
  const [profile, setProfile] = useState<Profile>({ imageUrl: "", text: "" })
  const [isEditing, setIsEditing] = useState(false)
  const [editProfile, setEditProfile] = useState<Profile>({ imageUrl: "", text: "" })
  const [mounted, setMounted] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    let active = true

    const loadProfile = async () => {
      setMounted(true)
      await hydrateStore()

      if (!active) return

      const storedProfile = getProfile()
      setProfile(storedProfile)
      setEditProfile(storedProfile)
    }

    void loadProfile()

    return () => {
      active = false
    }
  }, [])

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    const reader = new FileReader()
    reader.onload = (event) => {
      const img = new window.Image()
      img.src = event.target?.result as string
      img.onload = () => {
        const canvas = document.createElement("canvas")
        let width = img.width
        let height = img.height

        // 이미지 크기 제한 (최대 800px)
        const MAX_SIZE = 800
        if (width > height) {
          if (width > MAX_SIZE) {
            height *= MAX_SIZE / width
            width = MAX_SIZE
          }
        } else {
          if (height > MAX_SIZE) {
            width *= MAX_SIZE / height
            height = MAX_SIZE
          }
        }

        canvas.width = width
        canvas.height = height
        const ctx = canvas.getContext("2d")
        ctx?.drawImage(img, 0, 0, width, height)

        // WebP 압축 품질 70%로 저장
        const compressedBase64 = canvas.toDataURL("image/webp", 0.7)
        
        try {
          const newProfile = { ...profile, imageUrl: compressedBase64 }
          setProfile(newProfile)
          saveProfile(newProfile)
        } catch (error) {
          alert("이미지 용량이 너무 커서 저장할 수 없습니다. 더 작은 이미지를 선택해주세요.")
          console.error(error)
        }
      }
    }
    reader.readAsDataURL(file)
  }

  const handleSaveText = () => {
    const newProfile = { ...editProfile, imageUrl: profile.imageUrl }
    setProfile(newProfile)
    saveProfile(newProfile)
    setIsEditing(false)
  }

  const handleCancelEdit = () => {
    setEditProfile(profile)
    setIsEditing(false)
  }

  const handleChange = (field: keyof Profile, value: string) => {
    setEditProfile((prev: Profile) => ({ ...prev, [field]: value }))
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl md:text-3xl font-bold text-foreground">작가 프로필</h1>
        {mounted && !isAdmin && <AdminLoginDialog><span /></AdminLoginDialog>}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="md:col-span-1">
          <div className="relative aspect-square rounded-xl overflow-hidden bg-muted">
            {profile.imageUrl ? (
              <Image src={profile.imageUrl} alt="Profile" fill className="object-cover" />
            ) : (
              <div className="w-full h-full flex items-center justify-center">
                <div className="text-center text-muted-foreground">
                  <Camera className="w-12 h-12 mx-auto mb-2" />
                  <p className="text-sm">프로필 이미지 없음</p>
                </div>
              </div>
            )}
            {mounted && isAdmin && (
              <button
                onClick={() => fileInputRef.current?.click()}
                className="absolute inset-0 bg-foreground/50 opacity-0 hover:opacity-100 transition-opacity flex items-center justify-center"
              >
                <div className="text-center text-background">
                  <Camera className="w-8 h-8 mx-auto mb-2" />
                  <p className="text-sm font-medium">이미지 변경</p>
                </div>
              </button>
            )}
          </div>
          <input ref={fileInputRef} type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
        </div>

        <div className="md:col-span-2 space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-semibold">소개</h2>
            {mounted && isAdmin && !isEditing && (
              <Button variant="ghost" size="sm" onClick={() => { setEditProfile(profile); setIsEditing(true); }}>
                <Edit2 className="w-4 h-4 mr-2" />
                수정
              </Button>
            )}
          </div>

          {isEditing ? (
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>필명 혹은 실명</Label>
                <Input value={editProfile.name || ""} onChange={(e) => handleChange("name", e.target.value)} placeholder="이름을 입력하세요" />
              </div>
              <div className="space-y-2">
                <Label>한줄 소개</Label>
                <Input value={editProfile.shortIntro || ""} onChange={(e) => handleChange("shortIntro", e.target.value)} placeholder="자신을 한줄로 표현해주세요" />
              </div>
              <div className="space-y-2">
                <Label>경력</Label>
                <Textarea value={editProfile.experience || ""} onChange={(e) => handleChange("experience", e.target.value)} placeholder="경력을 적어주세요 (줄바꿈 가능)" rows={3} />
              </div>
              <div className="space-y-2">
                <Label>대표작</Label>
                <Textarea value={editProfile.representativeWorks || ""} onChange={(e) => handleChange("representativeWorks", e.target.value)} placeholder="대표 작품들을 적어주세요 (줄바꿈 가능)" rows={3} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>이메일</Label>
                  <Input type="email" value={editProfile.email || ""} onChange={(e) => handleChange("email", e.target.value)} placeholder="연락처 이메일" />
                </div>
                <div className="space-y-2">
                  <Label>SNS</Label>
                  <Input value={editProfile.sns || ""} onChange={(e) => handleChange("sns", e.target.value)} placeholder="인스타그램, 트위터 링크 등" />
                </div>
              </div>
              <div className="space-y-2">
                <Label>상세 소개</Label>
                <Textarea value={editProfile.text || ""} onChange={(e) => handleChange("text", e.target.value)} placeholder="자기소개를 자세히 작성해주세요..." rows={8} className="resize-none" />
              </div>
              <div className="flex gap-2">
                <Button onClick={handleSaveText} className="gap-2">
                  <Save className="w-4 h-4" /> 저장
                </Button>
                <Button variant="ghost" onClick={handleCancelEdit} className="gap-2">
                  <X className="w-4 h-4" /> 취소
                </Button>
              </div>
            </div>
          ) : (
            <div className="p-6 bg-card rounded-xl border border-border min-h-[300px] flex flex-col gap-6">
              {(profile.name || profile.shortIntro) ? (
                <div className="border-b pb-4">
                  <h3 className="text-2xl font-bold">{profile.name || "이름 없음"}</h3>
                  {profile.shortIntro && <p className="text-muted-foreground mt-1">{profile.shortIntro}</p>}
                </div>
              ) : (
                !(profile.experience || profile.representativeWorks || profile.email || profile.sns || profile.text) &&
                  <p className="text-muted-foreground text-center py-8">
                    아직 프로필 정보가 없습니다.
                    {mounted && isAdmin && " 위의 수정 버튼을 눌러 작성해주세요"}
                  </p>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {profile.experience && (
                  <div>
                    <h4 className="text-sm font-semibold mb-1">경력</h4>
                    <p className="text-sm whitespace-pre-wrap">{profile.experience}</p>
                  </div>
                )}
                {profile.representativeWorks && (
                  <div>
                    <h4 className="text-sm font-semibold mb-1">대표작</h4>
                    <p className="text-sm whitespace-pre-wrap">{profile.representativeWorks}</p>
                  </div>
                )}
              </div>

              {(profile.email || profile.sns) && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {profile.email && (
                    <div>
                      <h4 className="text-sm font-semibold mb-1">이메일</h4>
                      <p className="text-sm">{profile.email}</p>
                    </div>
                  )}
                  {profile.sns && (
                    <div>
                      <h4 className="text-sm font-semibold mb-1">SNS</h4>
                      <p className="text-sm">{profile.sns}</p>
                    </div>
                  )}
                </div>
              )}

              {profile.text && (
                <div>
                  <h4 className="text-sm font-semibold mb-1">상세 소개</h4>
                  <p className="text-sm whitespace-pre-wrap leading-relaxed">{profile.text}</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}